class Cart:
    def __init__(self):
        self._items = []
        self._discount_pct = 0

    def add(self, item, qty=1, unit_price=0.0):
        self._items.append((item, qty, unit_price))

    def line_total(self, idx):
        item, qty, unit_price = self._items[idx]
        return qty * unit_price

    def subtotal(self):
        return sum(qty * unit_price for _, qty, unit_price in self._items)

    def set_discount_pct(self, pct):
        self._discount_pct = pct

    def apply_discount(self, amount):
        return amount * (100 - self._discount_pct) / 100

    def total(self):
        return self.apply_discount(self.subtotal())
